import React, { useState, useRef } from "react";
import { useNavigate } from "react-router-dom";
import "../App.css";

const countryCodes = [
  { code: "+1", label: "🇺🇸 USA", value: "+1" },
  { code: "+44", label: "🇬🇧 UK", value: "+44" },
  { code: "+91", label: "🇮🇳 India", value: "+91" },
  { code: "+61", label: "🇦🇺 Australia", value: "+61" },
  { code: "+81", label: "🇯🇵 Japan", value: "+81" },
  { code: "+49", label: "🇩🇪 Germany", value: "+49" },
  { code: "+33", label: "🇫🇷 France", value: "+33" },
  { code: "+86", label: "🇨🇳 China", value: "+86" },
];

export default function Login({ onLogin }) {
  const navigate = useNavigate();
  const [countryCode, setCountryCode] = useState("+91");
  const [phone, setPhone] = useState("");
  const [otp, setOtp] = useState("");
  const [step, setStep] = useState(1); // 1: enter phone, 2: enter otp
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const verifyInProgress = useRef(false);

  const API_BASE = process.env.REACT_APP_API_BASE || "http://localhost:5000";

  const requestOtp = async () => {
    setLoading(true);
    setError("");
    setSuccess("");
    try {
      const contact = countryCode + phone;
      const res = await fetch(`${API_BASE}/api/auth/login`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ phone: contact }),
      });
      const data = await res.json();
      if (res.ok && data.success) {
        setSuccess("OTP sent successfully! 📱");
        setTimeout(() => {
          setStep(2);
          setSuccess("");
        }, 1500);
      } else {
        setError(data.message || "Failed to send OTP");
      }
    } catch (e) {
      setError("Network error. Please try again.");
    }
    setLoading(false);
  };

  const verifyOtp = async () => {
    if (verifyInProgress.current) {
      return;
    }
    verifyInProgress.current = true;
    setLoading(true);
    setError("");
    setSuccess("");
    try {
      const contact = countryCode + phone;
      const res = await fetch(`${API_BASE}/api/auth/verify-otp`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ phone: contact, otp }),
      });
      const data = await res.json();
      if (res.ok && data.success) {
        setSuccess("Login successful! 🎉");
        setTimeout(() => {
          onLogin(data.user || { phone: contact });
        }, 1500);
      } else {
        setError(data.message || "Invalid OTP");
      }
    } catch (e) {
      setError("Network error. Please try again.");
    }
    setLoading(false);
    verifyInProgress.current = false;
  };

  const handlePhoneChange = (e) => {
    const value = e.target.value;
    if (/^\d*$/.test(value)) {
      setPhone(value);
    }
  };

  const handleOtpChange = (e) => {
    const value = e.target.value;
    if (/^\d*$/.test(value)) {
      setOtp(value);
    }
  };

  return (
    <div className="auth-page">
      <div className="auth-background">
        <div className="floating-shapes">
          <div className="shape shape-1"></div>
          <div className="shape shape-2"></div>
          <div className="shape shape-3"></div>
        </div>
      </div>

      <div className="auth-container">
        <div className="auth-card">
          <div className="auth-header">
            <div className="auth-icon">🏠</div>
            <h1 className="auth-title">Smart Home</h1>
            <p className="auth-subtitle">Welcome back!</p>
          </div>

          <div className="auth-form-container">
            {step === 1 && (
              <div className="auth-step" key="step1">
                <div className="step-indicator">
                  <div className="step active">1</div>
                  <div className="step-line"></div>
                  <div className="step">2</div>
                </div>

                <div className="form-section">
                  <h2 className="form-title">Enter Phone Number</h2>
                  <p className="form-description">We'll send you a verification code</p>

                  <div className="input-group">
                    <label className="input-label">Phone Number</label>
                    <div className="phone-input-container">
                      <select
                        value={countryCode}
                        onChange={(e) => setCountryCode(e.target.value)}
                        disabled={loading}
                        className="country-select"
                      >
                        {countryCodes.map((c) => (
                          <option key={c.code} value={c.code}>
                            {c.label}
                          </option>
                        ))}
                      </select>
                      <input
                        type="text"
                        placeholder="Enter phone number"
                        value={phone}
                        onChange={handlePhoneChange}
                        disabled={loading}
                        className="phone-input"
                        maxLength="10"
                      />
                    </div>
                  </div>

                  <button
                    onClick={requestOtp}
                    disabled={loading || phone.length !== 10}
                    className={`auth-button primary ${loading || phone.length !== 10 ? 'disabled' : ''}`}
                  >
                    {loading ? (
                      <span className="button-content">
                        <div className="spinner"></div>
                        Sending OTP...
                      </span>
                    ) : (
                      <span className="button-content">
                        Send OTP 📱
                      </span>
                    )}
                  </button>
                </div>
              </div>
            )}

            {step === 2 && (
              <div className="auth-step" key="step2">
                <div className="step-indicator">
                  <div className="step completed">1</div>
                  <div className="step-line active"></div>
                  <div className="step active">2</div>
                </div>

                <div className="form-section">
                  <h2 className="form-title">Enter Verification Code</h2>
                  <p className="form-description">
                    We've sent a 4-digit code to {countryCode} {phone}
                  </p>

                  <div className="input-group">
                    <label className="input-label">OTP Code</label>
                    <input
                      type="text"
                      placeholder="Enter 4-digit code"
                      value={otp}
                      onChange={handleOtpChange}
                      disabled={loading}
                      className="otp-input"
                      maxLength="4"
                    />
                  </div>

                  <button
                    onClick={verifyOtp}
                    disabled={loading || !otp || otp.length !== 4}
                    className={`auth-button primary ${loading || otp.length !== 4 ? 'disabled' : ''}`}
                  >
                    {loading ? (
                      <span className="button-content">
                        <div className="spinner"></div>
                        Verifying...
                      </span>
                    ) : (
                      <span className="button-content">
                        Verify & Login 🚀
                      </span>
                    )}
                  </button>

                  <button
                    onClick={() => {
                      setStep(1);
                      setOtp("");
                      setError("");
                    }}
                    className="auth-button secondary"
                  >
                    ← Back to Phone
                  </button>
                </div>
              </div>
            )}

            {error && (
              <div className="alert error">
                <span className="alert-icon">⚠️</span>
                {error}
              </div>
            )}

            {success && (
              <div className="alert success">
                <span className="alert-icon">✅</span>
                {success}
              </div>
            )}

            <div className="auth-footer">
              <p>Don't have an account?</p>
              <button
                onClick={() => navigate('/register')}
                className="link-button"
              >
                Create Account →
              </button>
            </div>
          </div>
